  NAME '2025_of_nieuwer'
  INCLUDE 'connection/dataservices.inc'
  DATA "geometrie FROM (SELECT id, oorspronkelijk_bouwjaar, geometrie, ligging_omschrijving, type_woonobject, ('https://api.data.amsterdam.nl/v1/bag/panden/' || identificatie || '/?volgnummer=' || volgnummer::text) AS uri FROM public.bag_panden_v1 WHERE coalesce(eind_geldigheid, now()) >= now() AND status_omschrijving NOT IN ('Niet gerealiseerd pand', 'Pand gesloopt', 'Pand ten onrechte opgevoerd')) AS subquery USING srid=28992 USING UNIQUE id"
FILTER ([oorspronkelijk_bouwjaar] >= 2025)
  GROUP 'panden_naar_bouwjaar'
  TYPE POLYGON
  CLASSITEM       "oorspronkelijk_bouwjaar"
  LABELITEM       "oorspronkelijk_bouwjaar"
  TEMPLATE 'fooOnlyForWMSGetFeatureInfo.html'
  PROJECTION
    'init=epsg:28992'
  END
  METADATA
    'ows_title' '2025 of nieuwer'
    'ows_group_title' 'Panden naar bouwjaar'
    'wms_include_items' 'all'
    'ows_abstract' 'BAG panden van de gemeente Amsterdam, met leeftijd codering'
    'gml_featureid' 'ID'
    'gml_geometries' 'geometry'
    'gml_geometry_type' 'polygon'
    'gml_include_items' 'all'
  END
  CLASS
    NAME '2025 of nieuwer'
    STYLE
      COLOR '#002D4F'
      OPACITY 50
      OUTLINECOLOR '#002D4F'
      WIDTH  1
    END
    LABEL
      MINSCALEDENOM 10
      MAXSCALEDENOM 1000
      COLOR 0 0 0
      OUTLINECOLOR 255 255 255
      OUTLINEWIDTH 3
      FONT 'Ubuntu-M'
      TYPE truetype
      SIZE 10
      POSITION AUTO
      PARTIALS FALSE
    END
  END
END
